# dual explorer-H1 · S12-T2-B-E1
REQUIRED = {"lat", "lon", "provider"}
PRECALC = {"Lima": {"lat": -12.0464, "lon": -77.0428, "provider": "precalc"}}
def contract_ok(d):
    return not (REQUIRED - set(d.keys()))
def geocode(city, fail_online=False):
    if fail_online:
        return {**PRECALC[city], "mode": "offline_fallback"}
    return {"lat": -12.0464, "lon": -77.0428, "provider": "online", "mode": "online"}
print(contract_ok(geocode("Lima")))
print(geocode("Lima", fail_online=True)["mode"])

# dual explorer-H1 · S12-T2-B-E2
def validate_geo(d):
    for k in ("lat", "lon"):
        if k not in d:
            return False
        if not isinstance(d[k], (int, float)):
            return False
    return True
print(validate_geo({"lat": 1.0, "lon": 2.0}), validate_geo({"lat": "x"}))

