# dual explorer-H1 · S12-T3-B-E3
def unit_of_work(ops):
    done = []
    try:
        for op in ops:
            done.append(op())
        return done
    except Exception:
        return "rollback"
print(unit_of_work([lambda: 1, lambda: 2]))

